using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers only)
        group.MapGet("/", async (ApplicationDbContext db, HttpContext context) =>
        {
            if (!context.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => MapToDto(s))
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Get shipments for the current customer
        group.MapGet("/my", async (ApplicationDbContext db, HttpContext context) =>
        {
            var email = context.User.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value
                ?? context.User.FindFirst(System.Security.Claims.ClaimTypes.Name)?.Value;

            if (string.IsNullOrEmpty(email))
                return Results.Unauthorized();

            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => MapToDto(s))
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Track by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null)
                return Results.NotFound();

            return Results.Ok(MapToDto(shipment));
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db, HttpContext context) =>
        {
            if (!context.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = (int)request.NewStatus;
            if (request.NewStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db, HttpContext context) =>
        {
            if (!context.User.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = (int)dto.Status,
                ShippedDate = dto.ShippedDate == default ? DateTime.UtcNow : dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Description = dto.Description
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", MapToDto(shipment));
        });
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

