                    ShippedDate = DateTime.UtcNow.AddDays(-3),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                    CustomerEmail = "customer@example.com",
                    Description = "Electronics - Laptop"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-2026-002",
                    Origin = "Shanghai, China",
                    Destination = "Sydney, Australia",
                    Status = 1, // PickedUp
                    ShippedDate = DateTime.UtcNow.AddDays(-1),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(7),
                    CustomerEmail = "customer@example.com",
                    Description = "Furniture - Office Desk"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-2026-003",
                    Origin = "Berlin, Germany",
                    Destination = "Tokyo, Japan",
                    Status = 3, // OutForDelivery
                    ShippedDate = DateTime.UtcNow.AddDays(-5),
                    EstimatedDelivery = DateTime.UtcNow,
                    CustomerEmail = "buyer@example.com",
                    Description = "Auto Parts"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-2026-004",
                    Origin = "São Paulo, Brazil",
                    Destination = "Miami, USA",
                    Status = 4, // Delivered
                    ShippedDate = DateTime.UtcNow.AddDays(-10),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(-3),
                    ActualDelivery = DateTime.UtcNow.AddDays(-4),
                    CustomerEmail = "buyer@example.com",
                    Description = "Coffee Beans - 50kg"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-2026-005",
                    Origin = "Mumbai, India",
                    Destination = "Dubai, UAE",
                    Status = 5, // Delayed
                    ShippedDate = DateTime.UtcNow.AddDays(-7),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                    CustomerEmail = "customer@example.com",
                    Description = "Textiles - Silk Fabric"
                }
            };

            db.Shipments.AddRange(shipments);
            await db.SaveChangesAsync();
        }
    }
