@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDeliveryDate;
    private string? createError;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto();
        estimatedDeliveryDate = DateTime.UtcNow.AddDays(5);
        createError = null;
    }

    private async Task CreateShipment()
    {
        createError = null;
        newShipment.EstimatedDelivery = estimatedDeliveryDate;
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreateForm = false;
            await LoadShipments();
        }
        else
        {
            createError = $"Failed to create shipment: {response.StatusCode}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusInt))
        {
            var newStatus = (ShipmentStatus)statusInt;
            var request = new UpdateShipmentStatusRequest { NewStatus = newStatus };
            var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status", request);
            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
                if (newStatus == ShipmentStatus.Delivered)
                    shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

    private string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}
