@page "/tracking"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveWebAssembly
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h3>Track Your Shipment</h3>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (trackedShipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@trackedShipment.TrackingNumber</h5>
            <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Description:</strong> @trackedShipment.Description</p>
                    <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                    <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong>
                        @if (trackedShipment.EstimatedDelivery.HasValue)
                        {
                            <span class="@(trackedShipment.EstimatedDelivery < DateTime.UtcNow && trackedShipment.Status != ShipmentStatus.Delivered ? "text-danger fw-bold" : "")">
                                @trackedShipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")
                            </span>
                        }
                        else
                        {
                            <span class="text-muted">Not available</span>
                        }
                    </p>
                    @if (trackedShipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> <span class="text-success">@trackedShipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</span></p>
                    }
                </div>
            </div>

            <!-- Progress visualization -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(trackedShipment.Status))%">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h4>My Shipments</h4>

@if (myShipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p class="text-muted">No shipments found for your account.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 @(shipment.Status == ShipmentStatus.Delayed ? "border-danger" : "")">
                    <div class="card-body">
                        <h6 class="card-title">@shipment.TrackingNumber</h6>
                        <p class="card-text text-muted mb-1">@shipment.Description</p>
                        <p class="mb-1"><small>@shipment.Origin → @shipment.Destination</small></p>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                        @if (shipment.EstimatedDelivery.HasValue && shipment.Status != ShipmentStatus.Delivered)
                        {
                            <p class="mt-2 mb-0"><small><strong>ETA:</strong> @shipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</small></p>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => TrackById(shipment.TrackingNumber)">
                            View Details
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string trackingNumber = "";
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private string? errorMessage;
    private bool isLoading;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/my");
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        errorMessage = null;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check the tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "An error occurred while tracking. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task TrackById(string tracking)
    {
        trackingNumber = tracking;
        await TrackShipment();
    }

    private int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        ShipmentStatus.Returned => 100,
        _ => 0
    };

    private string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
